from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a building into a single fluent sentence.
    """
    if not triples:
        return ""

    # Group triples by subject to identify the main building
    by_subject = {}
    for t in triples:
        if t.subject not in by_subject:
            by_subject[t.subject] = []
        by_subject[t.subject].append(t)

    # Find the main subject (the one with most triples)
    main_subject = max(by_subject.keys(), key=lambda s: len(by_subject[s]))
    main_triples = by_subject[main_subject]

    # Create a mapping of predicates to their objects for the main subject
    pred_to_obj = {}
    for t in main_triples:
        pred_to_obj[t.predicate] = t.object

    # Build sentence parts based on predicate categories
    parts = []

    # Start with building type/name
    if "buildingType" in pred_to_obj:
        parts.append(f"{main_subject} is a {pred_to_obj['buildingType']}")
    else:
        parts.append(main_subject)

    # Add architectural information
    if "architecturalStyle" in pred_to_obj:
        parts.append(f"with {pred_to_obj['architecturalStyle'].lower()} architecture")

    if "architect" in pred_to_obj:
        parts.append(f"designed by {pred_to_obj['architect']}")

    # Add location information
    location_parts = []
    if "address" in pred_to_obj:
        location_parts.append(f"at {pred_to_obj['address']}")
    if "location" in pred_to_obj:
        location_parts.append(f"located at {pred_to_obj['location']}")
    if "country" in pred_to_obj:
        location_parts.append(f"in {pred_to_obj['country']}")
    if "region" in pred_to_obj:
        location_parts.append(f"in {pred_to_obj['region']}")
    if "state" in pred_to_obj:
        location_parts.append(f"in {pred_to_obj['state']}")

    if location_parts:
        parts.append(", ".join(location_parts))

    # Add size information
    if "floorCount" in pred_to_obj:
        parts.append(f"with {pred_to_obj['floorCount']} floors")
    if "numberOfRooms" in pred_to_obj:
        parts.append(f"containing {pred_to_obj['numberOfRooms']} rooms")
    if "height" in pred_to_obj:
        parts.append(f"standing {pred_to_obj['height']} metres tall")
    if "floorArea" in pred_to_obj:
        parts.append(f"covering {pred_to_obj['floorArea']} square metres")

    # Add construction information
    if "yearOfConstruction" in pred_to_obj:
        parts.append(f"built in {pred_to_obj['yearOfConstruction']}")
    elif "buildingStartDate" in pred_to_obj:
        parts.append(f"construction began in {pred_to_obj['buildingStartDate']}")

    if "completionDate" in pred_to_obj:
        parts.append(f"completed in {pred_to_obj['completionDate']}")

    if "cost" in pred_to_obj:
        parts.append(f"with a cost of {pred_to_obj['cost']}")

    if "owner" in pred_to_obj:
        parts.append(f"owned by {pred_to_obj['owner']}")

    # Join all parts into a coherent sentence
    sentence = " ".join(parts)

    # Ensure proper capitalization and punctuation
    sentence = sentence[0].upper() + sentence[1:]
    if not sentence.endswith('.'):
        sentence += '.'

    return sentence

